import { useState } from "react";
import { Card, AddCard, TodoCard } from "./Card";

const TodoBox = function ({ handleModal, todos, setTodos }) {
    const [status, setStatus] = useState("");
    // const handleBackColour = function (_status) {
    //     setStatus((prv) => _status);
    // };
    return (
        <>
            <div className="todo-box">
                <Card cl={"add-card"}>
                    <AddCard handleModal={handleModal} />
                </Card>
                {todos.map((todo) => {
                    return (
                        <Card cl={"todo-card"} status={status} key={todo.id}>
                            <TodoCard
                                todos={todos}
                                todo={todo}
                                status={status}
                                setTodos={setTodos}
                                setStatus={setStatus}
                            />
                        </Card>
                    );
                })}
            </div>
        </>
    );
};
export default TodoBox;
